def known do
  @known_errors
end

def actions do
  @actions
end

def bind(name, options) when is_list(options) do
  Enum.reduce_while(@option_parsers, name, fn type, state ->
    case parse_type(type, state, options) do
      cache() = cache -> {:cont, cache}
      error -> {:halt, error}
    end
  end)
end

def build(options \\ []) do
  [
    {@header, [options |> Keyword.get(:where, true) |> map_clauses],
     [options |> Keyword.get(:output, :entry) |> map_clauses |> clean_return]}
  ]
end

def nodes(cache(router: router(module: module, state: state))) do
  {:ok, module.nodes(state)}
end

