def unary_op(op) do
  cond do
    op in [:&, :...] -> {:non_associative, 90}
    op in [:!, :^, :not, :+, :-, :"~~~"] -> {:non_associative, 300}
    op in [:@] -> {:non_associative, 320}
    true -> :error
  end
end

def flat_map_reduce(enumerable, acc, fun) do
  {_, {list, acc}} =
    Enumerable.reduce(enumerable, {:cont, {[], acc}}, fn entry, {list, acc} ->
      case fun.(entry, acc) do
        {:halt, acc} -> {:halt, {list, acc}}
        {[], acc} -> {:cont, {list, acc}}
        {[entry], acc} -> {:cont, {[entry | list], acc}}
        {entries, acc} -> {:cont, {reduce(entries, list, &[&1 | &2]), acc}}
      end
    end)

  {:lists.reverse(list), acc}
end

