  hub_stops =
    @hub_map
    |> Map.get(route_id)
    |> Task.async_stream(&build_hub_stop(&1, detailed_stops))
    |> Enum.map(fn {:ok, hub_stop} -> hub_stop end)

  {route_id, hub_stops}
end
